! function () {
  const e = document.documentElement;
  if (e.classList.remove("no-js"), e.classList.add("js"), document.body.classList.contains("has-animations")) {
    const e = window.sr = ScrollReveal();
    e.reveal(".hero-title, .hero-paragraph, .newsletter-header, .newsletter-form", {
      duration: 1e3,
      distance: "40px",
      easing: "cubic-bezier(0.5, -0.01, 0, 1.005)",
      origin: "bottom",
      interval: 150
    }), e.reveal(".bubble-3, .bubble-4, .hero-browser-inner, .bubble-1, .bubble-2", {
      duration: 1e3,
      scale: .95,
      easing: "cubic-bezier(0.5, -0.01, 0, 1.005)",
      interval: 15
        }), e.reveal(".feature", {
        duration: 600,
        distance: "40px",
        easing: "cubic-bezier(0.5, -0.01, 0, 1.005)",
        interval: 100,
        origin: "bottom",
        viewFactor: .5
      })
  }
}();

function times(n) {
  return Array.apply(null, new Array(n));
}

function seq(e, i) {
  return i + 3;
}

function seqDates(e, i) {
  return i + 2000;
}

function random() {
  return Math.ceil(Math.random() * (60 - 30 + 1) + 30);
}

// OLD MOBILE
if (window.innerWidth < 320) {
  var seriesCount = 3;
}
// MOBILE
else if (window.innerWidth < 700) {
  var seriesCount = 6;
}
// TABLET
else if (window.innerWidth < 991) {
  var seriesCount = 10;
}
// DESKTOP
else {
  var seriesCount = 18;
}

var chart = new Chartist.Line('.ct-chart', {
  labels: times(seriesCount).map(seqDates),
  series: [
    times(seriesCount).map(random),
    times(seriesCount).map(random)
  ]
}, {
  fullWidth: true,
  high: 70,
  low: 20,
  width: '96%',
  showArea: true,
    showLine: true,
    axisX: {
      showLabel: true,
      offset: 15
    },
    axisY: {
      showGrid: false,
      showLabel: false,
      offset: 23
    }
  });

var seq = 0;

chart.on('created', function () {
  seq = 0;
});

chart.on('draw', function(data) {
  if(data.type === 'line' || data.type === 'area') {
    data.element.animate({
      d: {
        begin: 2000 * data.index,
        dur: 2000,
        from: data.path.clone().scale(1, 0).translate(0, data.chartRect.height()).stringify(),
        to: data.path.clone().stringify(),
        easing: Chartist.Svg.Easing.easeOutQuint
      }
    });
  }
  if (data.type === 'point') {
    seq++;

    data.element.animate({
      x1: {
        from: data.x - 50,
        to: data.x,
        begin: seq * 50,
        dur: 800,
        easing: Chartist.Svg.Easing.easeOutQuint
      },
      opacity: {
        from: 0,
        to: 1,
        begin: seq * 60,
        dur: 300,
      }
    });
  }
});

chart.on('created', function() {
  if(window.__exampleAnimateTimeout) {
    clearTimeout(window.__exampleAnimateTimeout);
    window.__exampleAnimateTimeout = null;
  }
  window.__exampleAnimateTimeout = setTimeout(chart.update.bind(chart), 7070);
});

